mapper.select:
SELECT s.id, s.user_id, u.real_name AS nick_name, u.avatar, s.session_name, s.agent_code, s.status, (SELECT COUNT(*) FROM ai_chat_record r WHERE r.session_id = s.id) AS message_count, (SELECT COALESCE(SUM(r.token_usage), 0) FROM ai_chat_record r WHERE r.session_id = s.id) AS token_usage, s.create_time, s.update_time FROM ai_chat_session s LEFT JOIN sys_user u ON s.user_id = u.id
1=1 AND s.status = '0'
AND (u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR s.session_name LIKE CONCAT('%', #{query.keyword}, '%'))
AND s.create_time >= #{query.startTime}
AND s.create_time <= CONCAT(#{query.endTime}, ' 23:59:59')
AND s.status = #{query.status}
AND s.agent_code = #{query.agentCode}
ORDER BY s.update_time DESC
